mapper.select:
SELECT j.id, j.company_id, j.title, j.type, j.industry, j.location, j.min_salary, j.max_salary, j.education, j.experience, j.requirements, j.responsibilities, j.benefits, j.deadline, j.status, j.created_at, j.updated_at, cp.company_name AS company_name FROM jobs j LEFT JOIN company_profiles cp ON cp.id = j.company_id WHERE j.status = 'PUBLISHED'
AND (j.title LIKE CONCAT('%', #{keyword}, '%') OR j.requirements LIKE CONCAT('%', #{keyword}, '%'))
AND j.location = #{location}
AND j.industry = #{industry}
ORDER BY j.created_at DESC
